#include "TaskComponentDataFactory.h"
#include "ArgusEditorModule.h"

UTaskComponentDataFactory::UTaskComponentDataFactory(const FObjectInitializer& objectInitializer)
{
	SupportedClass = UTaskComponentData::StaticClass();
	bEditAfterNew = true;
	bCreateNew = true;
}

UObject* UTaskComponentDataFactory::FactoryCreateNew(UClass* classDefinition, UObject* parentObject, FName name, EObjectFlags objectFlags, UObject* context, FFeedbackContext* warning)
{
	if (!ensure(classDefinition) || !ensure(classDefinition->IsChildOf(SupportedClass)))
	{
		return nullptr;
	}

	return NewObject<UObject>(parentObject, SupportedClass, name, objectFlags | RF_Transactional, context);
}

uint32 FAssetTypeActions_TaskComponentData::GetCategories()
{
	return ArgusEditorModule::GetAssetTypeCategory();
}
